from typing import List, TypedDict


class Item(TypedDict):
    price: float
    quantity: int


class CustomerInfo(TypedDict):
    type: str
    years: int


class OrderSummary(TypedDict):
    total: float
    discount: float
    final: float


def calculate_discount(price: float, customer_type: str, years_member: int) -> float:
    if customer_type == "premium":
        discount = 0.2
    elif customer_type == "standard":
        discount = 0.1
    else:
        discount = 0.0

    if years_member > 5:
        discount += 0.05

    final_price = price * (1 - discount)
    return final_price


def process_order(items: List[Item], customer_info: CustomerInfo) -> OrderSummary:
    total = 0
    for item in items:
        total += item['price'] * item['quantity']

    discount = calculate_discount(total, customer_info['type'], customer_info['years'])

    return {
        'total': total,
        'discount': discount,
        'final': total - discount
    }
